package ir.tahamohamadi.publication.api.admin;
import com.fasterxml.jackson.databind.ObjectMapper; import ir.tahamohamadi.audit.event.*; import ir.tahamohamadi.common.audit.AuthenticatedAuditActor; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.media.asset.*; import ir.tahamohamadi.publication.*; import org.springframework.data.domain.*; import org.springframework.orm.ObjectOptimisticLockingFailureException; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.time.Instant; import java.util.*; import java.util.stream.Collectors;
@Service @Transactional public class AdminPublicationService { private final PublicationRepository publications; private final PublicationTranslationRepository translations; private final MediaAssetRepository media; private final AuditEventRepository audit; private final ObjectMapper mapper; private final AuthenticatedAuditActor actor; public AdminPublicationService(PublicationRepository publications,PublicationTranslationRepository translations,MediaAssetRepository media,AuditEventRepository audit,ObjectMapper mapper,AuthenticatedAuditActor actor){this.publications=publications;this.translations=translations;this.media=media;this.audit=audit;this.mapper=mapper;this.actor=actor;}
@Transactional(readOnly=true) public Page<AdminPublicationSummary> list(int page,int size,String sort){Pageable pageable=paging(page,size,sort);Page<Publication> values=publications.findByDeletedAtIsNull(pageable);Map<UUID,List<PublicationTranslation>> byId=translations.findByPublicationIdInAndDeletedAtIsNull(values.getContent().stream().map(Publication::getId).toList()).stream().collect(Collectors.groupingBy(t->t.getPublication().getId()));return values.map(p->summary(p,byId.getOrDefault(p.getId(),List.of())));}
@Transactional(readOnly=true) public AdminPublicationResponse get(UUID id){return response(publication(id));} public AdminPublicationResponse create(AdminPublicationRequest r){actor.required();Instant now=Instant.now();Publication p=Publication.create(UUID.randomUUID(),r.publicationKey(),r.publicationStage(),r.year(),r.sortOrder(),now);p.update(r.publicationKey(),r.publicationStage(),r.doi(),r.externalUrl(),r.publishedOn(),r.year(),cover(r.coverMediaId()),r.sortOrder(),now);p=publications.save(p);saveTranslations(p,r,now);publications.flush();record("ADMIN_PUBLICATION_CREATED",p.getId());return response(p);} public AdminPublicationResponse update(UUID id,AdminPublicationRequest r){Publication p=publication(id);version(p,r.version());Instant now=Instant.now();p.update(r.publicationKey(),r.publicationStage(),r.doi(),r.externalUrl(),r.publishedOn(),r.year(),cover(r.coverMediaId()),r.sortOrder(),now);saveTranslations(p,r,now);publications.flush();record("ADMIN_PUBLICATION_UPDATED",id);return response(p);} public AdminPublicationResponse publish(UUID id,long requested){Publication p=publication(id);version(p,requested);requireReady(p);p.publish(Instant.now());publications.flush();record("ADMIN_PUBLICATION_PUBLISHED",id);return response(p);} public AdminPublicationResponse archive(UUID id,long requested){Publication p=publication(id);version(p,requested);p.archive(Instant.now());publications.flush();record("ADMIN_PUBLICATION_ARCHIVED",id);return response(p);} public void delete(UUID id,long requested){Publication p=publication(id);version(p,requested);p.softDelete(actor.required(),Instant.now());publications.flush();record("ADMIN_PUBLICATION_DELETED",id);}
private Publication publication(UUID id){return publications.findById(id).filter(p->p.getDeletedAt()==null).orElseThrow(()->new NoSuchElementException("Publication not found"));} private MediaAsset cover(UUID id){if(id==null)return null;return media.findByIdAndStatusAndDeletedAtIsNull(id,MediaAssetStatus.ACTIVE).orElseThrow(()->new NoSuchElementException("Media asset not found"));} private void saveTranslations(Publication p,AdminPublicationRequest r,Instant now){List<PublicationTranslation> existing=translations.findByPublicationIdAndDeletedAtIsNull(p.getId());saveTranslation(p,existing,LanguageCode.fa,r.fa(),now);saveTranslation(p,existing,LanguageCode.en,r.en(),now);} private void saveTranslation(Publication p,List<PublicationTranslation> existing,LanguageCode language,AdminPublicationTranslationRequest r,Instant now){existing.stream().filter(t->t.getLanguageCode()==language).findFirst().ifPresentOrElse(t->t.update(r.title(),r.slug(),r.abstractText(),r.authorsDisplay(),r.venueDisplay(),r.seoTitle(),r.seoDescription(),now),()->translations.save(PublicationTranslation.create(UUID.randomUUID(),p,language,r.title(),r.slug(),r.abstractText(),r.authorsDisplay(),r.venueDisplay(),r.seoTitle(),r.seoDescription(),now)));} private void requireReady(Publication p){if(p.getPublishedOn()==null||translations.findByPublicationIdAndDeletedAtIsNull(p.getId()).size()!=2)throw new IllegalArgumentException("Publication requires published date and both translations");} private AdminPublicationResponse response(Publication p){List<PublicationTranslation> t=translations.findByPublicationIdAndDeletedAtIsNull(p.getId());return new AdminPublicationResponse(p.getId(),p.getPublicationKey(),p.getPublicationStage(),p.getContentStatus().name(),p.getDoi(),p.getExternalUrl(),p.getPublishedOn(),p.getYear(),p.getCoverMedia()==null?null:p.getCoverMedia().getId(),p.getSortOrder(),translation(t,LanguageCode.fa),translation(t,LanguageCode.en),p.getVersion());} private AdminPublicationSummary summary(Publication p,List<PublicationTranslation> t){return new AdminPublicationSummary(p.getId(),p.getPublicationKey(),p.getPublicationStage(),p.getContentStatus().name(),p.getYear(),p.getSortOrder(),translation(t,LanguageCode.fa),translation(t,LanguageCode.en),p.getVersion());} private AdminPublicationTranslationRequest translation(List<PublicationTranslation> t,LanguageCode language){return t.stream().filter(x->x.getLanguageCode()==language).findFirst().map(value->new AdminPublicationTranslationRequest(value.getTitle(),value.getSlug(),value.getAbstractText(),value.getAuthorsDisplay(),value.getVenueDisplay(),value.getSeoTitle(),value.getSeoDescription())).orElse(null);} private static void version(Publication p,Long requested){if(requested==null||p.getVersion()!=requested)throw new ObjectOptimisticLockingFailureException(Publication.class,p.getId());} private static Pageable paging(int page,int size,String requested){String[] p=requested.split(",",-1);if(p.length!=2||!Set.of("updatedAt","year","sortOrder","publicationKey").contains(p[0]))throw new IllegalArgumentException("Unsupported sort");try{return PageRequest.of(page,size,Sort.by(Sort.Direction.fromString(p[1]),p[0]).and(Sort.by("id")));}catch(IllegalArgumentException e){throw new IllegalArgumentException("Unsupported sort");}} private void record(String action,UUID id){audit.save(AuditEvent.record(UUID.randomUUID(),Instant.now(),actor.required(),action,"PUBLICATION",id,"SUCCESS",null,null,mapper.createObjectNode().put("changedFields","managed")));} }
